import{_ as o,o as e,c as r,ae as t}from"./chunks/framework.BzQXgbNp.js";const l="/assets/dash-6.C7I2FlRM.png",u=JSON.parse('{"title":"🔒 密碼安全箱設定與網頁端白名單管理","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Password-Lock.md","filePath":"Web-Password-Lock.md"}'),i={name:"Web-Password-Lock.md"};function s(n,a,d,c,h,g){return e(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="🔒-密碼安全箱設定與網頁端白名單管理" tabindex="-1">🔒 密碼安全箱設定與網頁端白名單管理 <a class="header-anchor" href="#🔒-密碼安全箱設定與網頁端白名單管理" aria-label="Permalink to &quot;🔒 密碼安全箱設定與網頁端白名單管理&quot;">​</a></h1><p>安全密碼鎖系統可讓您為個人的貴重箱子（或木桶）提供雙重保護。即使該箱子沒有位於您的領地內，只要上鎖後，其餘人一概無法開啟或破壞。</p><hr><h2 id="🎮-1-遊戲內設定密碼鎖" tabindex="-1">🎮 1. 遊戲內設定密碼鎖 <a class="header-anchor" href="#🎮-1-遊戲內設定密碼鎖" aria-label="Permalink to &quot;🎮 1. 遊戲內設定密碼鎖&quot;">​</a></h2><h3 id="【步驟一】發起上鎖" tabindex="-1">【步驟一】發起上鎖 <a class="header-anchor" href="#【步驟一】發起上鎖" aria-label="Permalink to &quot;【步驟一】發起上鎖&quot;">​</a></h3><ol><li>站在您想要上鎖的箱子（或木桶）前。</li><li>雙眼看著該箱子（距離必須在 4.5 格內）。</li><li>在聊天欄輸入指令：<strong><code>/padlock</code></strong>。</li><li>系統會攔截您的下一次聊天發言，並在聊天欄顯示提示：<code>§b[Craft-Core] §f請輸入密碼以設定密碼鎖：</code>。</li></ol><h3 id="【步驟二】輸入密碼" tabindex="-1">【步驟二】輸入密碼 <a class="header-anchor" href="#【步驟二】輸入密碼" aria-label="Permalink to &quot;【步驟二】輸入密碼&quot;">​</a></h3><ul><li>直接在聊天欄打出您想要設定的密碼並按 Enter 發送（該訊息會被系統攔截，不會被其他玩家看見）。</li><li>設定完成後會播放 Chest Locked 聲效並顯示：<code>§b[Craft-Core] §a密碼鎖設定成功！</code>。</li></ul><hr><h2 id="👥-2-共享與白名單授權" tabindex="-1">👥 2. 共享與白名單授權 <a class="header-anchor" href="#👥-2-共享與白名單授權" aria-label="Permalink to &quot;👥 2. 共享與白名單授權&quot;">​</a></h2><p>上鎖後的箱子，預設僅有<strong>您本人</strong>與**管理員(OP)**可以開啟。若要讓好友免密碼直接開啟：</p><h3 id="遊戲內授權指令" tabindex="-1">遊戲內授權指令： <a class="header-anchor" href="#遊戲內授權指令" aria-label="Permalink to &quot;遊戲內授權指令：&quot;">​</a></h3><ol><li>站在該密碼箱前，看著它（4.5 格內）。</li><li>輸入指令：<strong><code>/padlock grant &lt;好友名稱&gt;</code></strong>。</li><li>系統即會成功將其加入授權名冊中。</li></ol><h3 id="網頁端白名單管理" tabindex="-1">網頁端白名單管理： <a class="header-anchor" href="#網頁端白名單管理" aria-label="Permalink to &quot;網頁端白名單管理：&quot;">​</a></h3><p>登入網頁儀表板後，點選 <strong>「密碼箱管理」</strong> 分頁，即可遠端對名下的所有安全箱進行管理：</p><ul><li><strong>新增授權白名單</strong>：直接在安全箱卡片中輸入好友的 Minecraft ID，將其加入白名單。</li><li><strong>撤銷授權</strong>：點選好友名字旁邊的 <strong><code>[ × ]</code></strong> 即可立刻取消其開啟權限。</li><li><strong>遠端修改密碼</strong>：點選「修改密碼」即可直接於網頁變更安全箱密碼。</li><li><strong>遠端註銷密碼鎖</strong>：點選「註銷密碼鎖」可將密碼箱回復成一般箱子。</li></ul><p><img src="'+l+'" alt="網頁密碼安全箱管理"></p>',17)])])}const _=o(i,[["render",s]]);export{u as __pageData,_ as default};
